func (a *adapter) SomeUpdate(ctx context.Context, in creditpurchase.SomeInput) (creditpurchase.SomeResult, error) {
	if err := in.Validate(); err != nil { return creditpurchase.SomeResult{}, err }
	return entutils.TransactingRepo(ctx, a, func(ctx context.Context, tx *adapter) (creditpurchase.SomeResult, error) {
		entity, err := tx.db.ChargeCreditPurchase.UpdateOneID(in.ID).Where(dbchargecreditpurchase.NamespaceEQ(in.Namespace)).Save(ctx)
		if err != nil { return creditpurchase.SomeResult{}, err }
		return MapCreditPurchaseChargeFromDB(entity, meta.ExpandNone)
	})
}

func (e *Engine) CalculateLines(input billing.CalculateLinesInput) (billing.StandardLines, error) {
	for _, stdLine := range input.Lines {
		if stdLine.ChargeID == nil { return nil, fmt.Errorf("credit purchase standard line[%s]: charge id is required", stdLine.ID) }
		generated, err := e.ratingService.GenerateDetailedLines(stdLine)
		if err != nil { return nil, fmt.Errorf("generating detailed lines for line[%s]: %w", stdLine.ID, err) }
		if err := invoicecalc.MergeGeneratedDetailedLines(stdLine, generated); err != nil { return nil, err }
	}
	return input.Lines, nil
}

func (s *service) SomeOperation(ctx context.Context, input creditpurchase.SomeInput) (creditpurchase.SomeResult, error) {
	if err := input.Validate(); err != nil { return creditpurchase.SomeResult{}, err }
	return transaction.Run(ctx, s.adapter, func(ctx context.Context) (creditpurchase.SomeResult, error) {
		ledgerRef, err := s.handler.OnSomeEvent(ctx, input.Charge)
		if err != nil { return creditpurchase.SomeResult{}, err }
		return s.adapter.SomeUpdate(ctx, input)
	})
}
